import React, { useEffect, useRef, useState } from "react";
import "../styles/GeneralChat.css";

const responses = [
  {
    keywords: ["alone", "lonely"],
    emotion: "💗 Empathy",
    reply:
      "Feeling lonely can be really painful. You’re not weak for feeling this way 🤍 Would you like to share what’s been making you feel alone?",
    songs: ["Alone – Alan Walker", "Fix You – Coldplay"],
  },
  {
    keywords: ["sad", "down", "low"],
    emotion: "🫂 Support",
    reply:
      "I hear you. Feeling sad can feel heavy and draining. I’m glad you reached out 💜",
    songs: ["Let It Be – Beatles", "Lovely – Billie Eilish"],
  },
  {
    keywords: ["exhausted", "tired", "burnout"],
    emotion: "😌 Care",
    reply:
      "Feeling exhausted usually means you’ve been carrying too much for too long. You deserve rest 🌙",
    songs: ["Weightless – Marconi Union", "Fix You – Coldplay"],
  },
  {
    keywords: ["hello", "hi", "hey"],
    emotion: "👋 Welcome",
    reply: "Hi! I’m here for you. How are you feeling today?",
    songs: [],
  },
];

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      emotion: "🧠 Welcome",
      text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
    },
  ]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);
  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typing]);

  const getBotReply = (userText) => {
    const msg = userText.toLowerCase();

    for (let item of responses) {
      if (item.keywords.some((k) => msg.includes(k))) {
        return {
          emotion: item.emotion,
          text:
            item.reply +
            (item.songs.length
              ? `\n\n🎵 Songs that may help:\n• ${item.songs.join("\n• ")}`
              : ""),
        };
      }
    }

    return {
      emotion: "🧠 Listening",
      text:
        "Thank you for telling me that 🤍 Can you tell me a little more about what you’re feeling right now?",
    };
  };

  const handleSend = () => {
    if (!input.trim()) return;

    setMessages((prev) => [...prev, { sender: "user", text: input }]);
    setInput("");
    setTyping(true);

    setTimeout(() => {
      const reply = getBotReply(input);
      setMessages((prev) => [
        ...prev,
        { sender: "bot", emotion: reply.emotion, text: reply.text },
      ]);
      setTyping(false);
    }, 1000);
  };

  return (
    <div className="chat-wrapper">
      <h2 className="chat-title">🧠 General Chat</h2>

      <div className="chat-container">
        {messages.map((msg, i) => (
          <div key={i} className={`bubble ${msg.sender}`}>
            {msg.sender === "bot" && (
              <div className="emotion">{msg.emotion}</div>
            )}
            <p style={{ whiteSpace: "pre-line" }}>{msg.text}</p>
          </div>
        ))}

        {typing && (
          <div className="bubble bot typing">
            <span></span>
            <span></span>
            <span></span>
          </div>
        )}

        <div ref={chatEndRef} />
      </div>

      <div className="input-area">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type how you feel..."
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
